1. When a significant change occurs (like logout), update localStorage with the new state:
javascript
localStorage.setItem('authStatus', 'loggedOut');


2. In all tabs, add an event listener that watches for storage changes:
javascript
window.addEventListener('storage', (event) => {
  if (event.key === 'authStatus' && event.newValue === 'loggedOut') {
    // Option 1: Show a notification then redirect
    alert('You have been logged out');
    window.location.href = '/login';

    // Option 2: Update UI state without reload
    // appState.setLoggedOut();
  }
});


Note: This event only fires in other tabs, not the one that made the change.

javascript
// In your main application file loaded in all tabs
const showLogoutNotification = () => {
  const notification = document.createElement('div');
  notification.textContent = 'You have been logged out from another tab';
  notification.style.cssText = 
    'position: fixed; top: 20px; right: 20px; padding: 15px; ' +
    'background: #ffebee; border: 1px solid #f44336; border-radius: 4px; ' +
    'color: #c62828; z-index: 1000;';

  document.body.appendChild(notification);
  setTimeout(() => notification.remove(), 5000);
};

window.addEventListener('storage', (event) => {
  if (event.key === 'authStatus' && event.newValue === 'loggedOut') {
    showLogoutNotification();
    // Optional: redirect after showing notification
    // setTimeout(() => window.location.href = '/login', 5000);
  }
});
